#pragma once
#include <stdint.h>

// ── API endpoints ────────────────────────────────────────────
//
//  The badge makes three independent GET requests on WiFi connect.
//  Server must respond with Content-Type: application/msgpack.
//
//  Caching: server should return an ETag header (file hash).
//  Badge stores ETags in NVS; subsequent requests send
//  If-None-Match: <etag>  →  server replies 304 if unchanged.
//
#define API_BASE_URL       "https://api.replay2026.com/v1"
#define API_URL_SCHEDULE   API_BASE_URL "/schedule"
#define API_URL_SPEAKERS   API_BASE_URL "/speakers"
#define API_URL_FLOORS     API_BASE_URL "/floors"
#define API_CONTENT_TYPE   "application/msgpack"

// ── Location codes  (floor_idx*100 + section_idx*10) ─────────
//
//  Decode on device:
//    floor_idx   = loc / 100
//    section_idx = (loc / 10) % 10
//
#define LOC_SWAG___LUNCH  0
#define LOC_THE_HANGAR  10
#define LOC_DEBARKMENT  100
#define LOC_PERSIST  110
#define LOC_GROUND_CONTROL  120
#define LOC_THE_GALLERY  130
#define LOC_HELP_DESK  140
#define LOC_SPONSORS_A  150
#define LOC_SPONSORS_B  160
#define LOC_SPONSORS_C  170
#define LOC_THE_EXPANSE  200
#define LOC_ELARA  210
#define LOC_ZENITH  220
#define LOC_HYPERION  230
#define LOC_PERSENNE  240
#define LOC_PULSAR  300
#define LOC_QUASAR  310
#define LOC_NEBULA  320
#define LOC_NOVA  330
#define LOC_SPEAKER_WORK_ROOM  400
#define LOC_TEMPORAL_OFFICE  410
#define LOC_TEMPORAL_FILM_STUDIO  420
#define LOC_SALES_MEETING_ROOMS  430
#define LOC_DESPINA  440
#define LOC_LOUNGE  450

// ── Event type constants ─────────────────────────────────────
#define EVT_TYPE_TALK       0
#define EVT_TYPE_WORKSHOP   1
#define EVT_TYPE_OTHER      2

// ── Structs ───────────────────────────────────────────────────
//
//  These are working buffers for a single parsed entry.
//  Do NOT store arrays of these — copy strings into your own
//  NVS / PSRAM buffers before the JsonDocument goes out of scope.
//
typedef struct {
    uint8_t     type;          // EVT_TYPE_*
    const char* title;
    uint16_t    start;         // HHMM  e.g. 1030 = 10:30
    uint16_t    end;
    uint16_t    loc;           // LOC_* macro above; 0 = no location
    const char* tags;          // comma-separated; nullptr if absent
    const char* desc;          // nullptr if absent
    uint8_t     speakers[8];   // speaker IDs
    uint8_t     speaker_count;
} ApiEvent;

typedef struct {
    uint8_t     id;
    const char* name;
    const char* co;            // company
    const char* title;
    const char* bio;           // empty string until populated
} ApiSpeaker;

typedef struct {
    uint8_t     idx;
    uint16_t    loc;
    const char* title;
    const char* alias;         // nullptr if absent
    const char* icon;          // nullptr if absent
    const char* desc;          // nullptr if absent
} ApiSection;

typedef struct {
    uint8_t     idx;
    const char* title;
    const char* desc;
    ApiSection  sections[10];
    uint8_t     section_count;
} ApiFloor;

